import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Profile, Book, Transaction, Category, DataContextType, 
  SyncFrequency, TransactionType 
} from '../types';
import { DEFAULT_CATEGORIES } from '../constants';
import { generateCSV, parseCSV, SAMPLE_CSV } from '../utils/csvHelper';

const DataContext = createContext<DataContextType | undefined>(undefined);

const STORAGE_KEY = 'expenSync_v1';

const INITIAL_PROFILE: Profile = {
  id: 'default_profile',
  name: 'Main User',
  isCurrent: true,
  themePreference: 'system',
  syncFrequency: SyncFrequency.OFF
};

const INITIAL_BOOK: Book = {
  id: 'default_book',
  profileId: 'default_profile',
  name: 'Personal Wallet',
  currency: 'USD',
  color: 'bg-blue-500'
};

export const DataProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [profiles, setProfiles] = useState<Profile[]>([]);
  const [books, setBooks] = useState<Book[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);

  // Load initial data
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      const parsed = JSON.parse(saved);
      setProfiles(parsed.profiles || [INITIAL_PROFILE]);
      setBooks(parsed.books || [INITIAL_BOOK]);
      setTransactions(parsed.transactions || []);
    } else {
      setProfiles([INITIAL_PROFILE]);
      setBooks([INITIAL_BOOK]);
      setTransactions([]);
    }
  }, []);

  // Save on change
  useEffect(() => {
    if (profiles.length > 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ profiles, books, transactions }));
    }
  }, [profiles, books, transactions]);

  const currentProfile = profiles.find(p => p.isCurrent) || profiles[0] || null;

  const addProfile = (name: string) => {
    const newProfile: Profile = {
      id: uuidv4(),
      name,
      isCurrent: true,
      themePreference: 'system',
      syncFrequency: SyncFrequency.OFF
    };

    // Set others to not current
    const updatedProfiles = profiles.map(p => ({ ...p, isCurrent: false }));
    setProfiles([...updatedProfiles, newProfile]);

    // Add a default book for new profile
    const newBook: Book = {
      id: uuidv4(),
      profileId: newProfile.id,
      name: 'My Wallet',
      currency: 'USD',
      color: 'bg-emerald-500'
    };
    setBooks(prev => [...prev, newBook]);
  };

  const switchProfile = (id: string) => {
    setProfiles(prev => prev.map(p => ({
      ...p,
      isCurrent: p.id === id
    })));
  };

  const updateProfileSettings = (id: string, updates: Partial<Profile>) => {
    setProfiles(prev => prev.map(p => p.id === id ? { ...p, ...updates } : p));
  };

  const addBook = (bookData: Omit<Book, 'id' | 'profileId'>) => {
    if (!currentProfile) return;
    const newBook: Book = {
      ...bookData,
      id: uuidv4(),
      profileId: currentProfile.id
    };
    setBooks(prev => [...prev, newBook]);
  };

  const deleteBook = (id: string) => {
    setBooks(prev => prev.filter(b => b.id !== id));
    setTransactions(prev => prev.filter(t => t.bookId !== id));
  };

  const addTransaction = (txData: Omit<Transaction, 'id' | 'createdAt'>) => {
    const newTx: Transaction = {
      ...txData,
      id: uuidv4(),
      createdAt: Date.now()
    };
    setTransactions(prev => [newTx, ...prev]);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const downloadTemplate = useCallback(() => {
    const blob = new Blob([SAMPLE_CSV], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'expenses_template.csv';
    a.click();
    window.URL.revokeObjectURL(url);
  }, []);

  const exportData = useCallback(() => {
    if (!currentProfile) return;
    // Filter transactions for current profile's books
    const profileBookIds = books.filter(b => b.profileId === currentProfile.id).map(b => b.id);
    const profileTransactions = transactions.filter(t => profileBookIds.includes(t.bookId));

    const csv = generateCSV(profileTransactions, books, DEFAULT_CATEGORIES);
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `expenses_${currentProfile.name.replace(/\s+/g, '_')}_${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
    window.URL.revokeObjectURL(url);
  }, [currentProfile, books, transactions]);

  const importData = async (csvText: string): Promise<{ success: boolean; message: string }> => {
    try {
      if (!currentProfile) throw new Error("No profile selected");

      const rows = parseCSV(csvText);
      const newTransactions: Transaction[] = [];
      let importedCount = 0;

      for (const row of rows) {
        // Find or create book (simple logic: find by name in current profile)
        let book = books.find(b => b.name === row['Book'] && b.profileId === currentProfile.id);

        // If book doesn't exist, we skip or could create. For safety, let's use the first available book if match fails, or skip
        if (!book) {
            // Option: Create book if not exists
            const newBookId = uuidv4();
            const newBook: Book = {
                id: newBookId,
                profileId: currentProfile.id,
                name: row['Book'] || 'Imported Book',
                currency: 'USD',
                color: 'bg-gray-500'
            };
            setBooks(prev => [...prev, newBook]);
            book = newBook;
        }

        const cat = DEFAULT_CATEGORIES.find(c => c.name === row['Category']) || DEFAULT_CATEGORIES[6]; // Default to Other

        if (row['Amount'] && row['Date']) {
            newTransactions.push({
                id: uuidv4(),
                bookId: book.id,
                amount: parseFloat(row['Amount']),
                type: row['Type'] === 'INCOME' ? TransactionType.INCOME : TransactionType.EXPENSE,
                categoryId: cat.id,
                date: row['Date'],
                note: row['Note'] || '',
                createdAt: Date.now()
            });
            importedCount++;
        }
      }

      setTransactions(prev => [...newTransactions, ...prev]);
      return { success: true, message: `Successfully imported ${importedCount} transactions.` };
    } catch (e: any) {
      return { success: false, message: e.message || "Failed to import CSV" };
    }
  };

  const value = {
    profiles,
    books,
    transactions,
    categories: DEFAULT_CATEGORIES,
    currentProfile,
    addProfile,
    switchProfile,
    updateProfileSettings,
    addBook,
    deleteBook,
    addTransaction,
    deleteTransaction,
    importData,
    exportData,
    downloadTemplate
  };

  return <DataContext.Provider value={value}>{children}</DataContext.Provider>;
};

export const useData = () => {
  const context = useContext(DataContext);
  if (!context) throw new Error("useData must be used within DataProvider");
  return context;
};

