import React, { useState, useRef } from 'react';
import { useData } from '../contexts/DataContext';
import { Moon, Sun, Monitor, Cloud, User, Download, Upload, FileText } from 'lucide-react';
import { SyncFrequency } from '../types';

const Settings: React.FC = () => {
  const { 
    profiles, 
    currentProfile, 
    updateProfileSettings, 
    switchProfile, 
    addProfile,
    exportData,
    importData,
    downloadTemplate
  } = useData();

  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncTime, setLastSyncTime] = useState<string | null>(null);
  const [newProfileName, setNewProfileName] = useState('');
  const [importStatus, setImportStatus] = useState<string>('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleThemeChange = (theme: 'light' | 'dark' | 'system') => {
    if (currentProfile) {
      updateProfileSettings(currentProfile.id, { themePreference: theme });
      // Apply class immediately for UX
      if (theme === 'dark' || (theme === 'system' && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
        document.documentElement.classList.add('dark');
      } else {
        document.documentElement.classList.remove('dark');
      }
    }
  };

  const handleSyncNow = () => {
    setIsSyncing(true);
    // Simulate API call
    setTimeout(() => {
      setIsSyncing(false);
      setLastSyncTime(new Date().toLocaleTimeString());
    }, 2000);
  };

  const handleCreateProfile = (e: React.FormEvent) => {
    e.preventDefault();
    if(newProfileName.trim()){
      addProfile(newProfileName);
      setNewProfileName('');
    }
  }

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const text = event.target?.result as string;
      const result = await importData(text);
      setImportStatus(result.message);
      setTimeout(() => setImportStatus(''), 5000);
    };
    reader.readAsText(file);
    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  if (!currentProfile) return null;

  return (
    <div className="space-y-8 animate-fade-in">
      <h2 className="text-2xl font-bold text-gray-900 dark:text-white">Settings</h2>

      {/* Profile Section */}
      <section className="bg-white dark:bg-cardbg rounded-2xl p-6 shadow-sm border border-gray-100 dark:border-gray-800">
        <h3 className="text-lg font-semibold mb-4 flex items-center gap-2 dark:text-white">
          <User className="text-primary-500" size={20} /> Profiles
        </h3>

        <div className="flex gap-2 overflow-x-auto pb-4 mb-4 no-scrollbar">
          {profiles.map(p => (
            <button
              key={p.id}
              onClick={() => switchProfile(p.id)}
              className={`flex-shrink-0 px-5 py-2 rounded-full border text-sm font-medium transition-colors ${p.id === currentProfile.id ? 'bg-primary-600 border-primary-600 text-white' : 'bg-gray-50 dark:bg-gray-800 border-gray-200 dark:border-gray-700 text-gray-600 dark:text-gray-300'}`}
            >
              {p.name}
            </button>
          ))}
        </div>

        <form onSubmit={handleCreateProfile} className="flex gap-2">
           <input 
             type="text" 
             value={newProfileName}
             onChange={e => setNewProfileName(e.target.value)}
             placeholder="New profile name..."
             className="flex-1 bg-gray-50 dark:bg-gray-800 border-none rounded-xl px-4 py-2 dark:text-white text-sm focus:ring-2 focus:ring-primary-500"
           />
           <button type="submit" disabled={!newProfileName} className="bg-gray-900 dark:bg-white dark:text-black text-white px-4 py-2 rounded-xl text-sm font-medium disabled:opacity-50">Create</button>
        </form>
      </section>

      {/* Appearance */}
      <section className="bg-white dark:bg-cardbg rounded-2xl p-6 shadow-sm border border-gray-100 dark:border-gray-800">
         <h3 className="text-lg font-semibold mb-4 flex items-center gap-2 dark:text-white">
          <Monitor className="text-purple-500" size={20} /> Appearance
        </h3>
        <div className="grid grid-cols-3 gap-3">
          {(['light', 'dark', 'system'] as const).map((mode) => (
            <button
              key={mode}
              onClick={() => handleThemeChange(mode)}
              className={`flex flex-col items-center justify-center p-3 rounded-xl border-2 transition-all ${currentProfile.themePreference === mode ? 'border-primary-500 bg-primary-50 dark:bg-primary-900/20' : 'border-transparent bg-gray-50 dark:bg-gray-800'}`}
            >
               {mode === 'light' && <Sun size={24} className="mb-2 text-orange-500" />}
               {mode === 'dark' && <Moon size={24} className="mb-2 text-indigo-500" />}
               {mode === 'system' && <Monitor size={24} className="mb-2 text-gray-500" />}
               <span className="capitalize text-sm font-medium dark:text-gray-300">{mode}</span>
            </button>
          ))}
        </div>
      </section>

      {/* Sync */}
      <section className="bg-white dark:bg-cardbg rounded-2xl p-6 shadow-sm border border-gray-100 dark:border-gray-800">
         <h3 className="text-lg font-semibold mb-4 flex items-center gap-2 dark:text-white">
          <Cloud className="text-blue-500" size={20} /> Drive Sync
        </h3>
        <div className="mb-4">
           <label className="block text-sm text-gray-600 dark:text-gray-400 mb-2">Auto-sync frequency</label>
           <select 
              value={currentProfile.syncFrequency}
              onChange={(e) => updateProfileSettings(currentProfile.id, { syncFrequency: e.target.value as SyncFrequency })}
              className="w-full bg-gray-50 dark:bg-gray-800 border-none rounded-xl px-4 py-3 dark:text-white"
           >
              <option value={SyncFrequency.IMMEDIATE}>Immediate</option>
              <option value={SyncFrequency.DAILY}>Daily</option>
              <option value={SyncFrequency.MONTHLY}>Monthly</option>
              <option value={SyncFrequency.OFF}>Off (Manual)</option>
           </select>
        </div>
        <button 
          onClick={handleSyncNow}
          disabled={isSyncing}
          className="w-full bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 font-medium py-3 rounded-xl flex items-center justify-center gap-2"
        >
          {isSyncing ? 'Syncing...' : 'Sync Now'}
        </button>
        {lastSyncTime && <p className="text-xs text-center text-gray-400 mt-2">Last synced: {lastSyncTime}</p>}
      </section>

      {/* Data Management */}
      <section className="bg-white dark:bg-cardbg rounded-2xl p-6 shadow-sm border border-gray-100 dark:border-gray-800 mb-20">
         <h3 className="text-lg font-semibold mb-4 flex items-center gap-2 dark:text-white">
          <FileText className="text-green-500" size={20} /> Data Management
        </h3>

        <div className="grid grid-cols-1 gap-3">
          <button 
             onClick={exportData}
             className="flex items-center justify-between px-4 py-3 bg-gray-50 dark:bg-gray-800 rounded-xl hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
          >
             <span className="flex items-center gap-2 text-gray-700 dark:text-gray-300">
                <Download size={18} /> Export to Excel (CSV)
             </span>
          </button>

          <div className="relative">
             <input 
               type="file" 
               accept=".csv"
               ref={fileInputRef}
               onChange={handleFileUpload}
               className="hidden" 
               id="csv-upload"
             />
             <label 
               htmlFor="csv-upload"
               className="flex items-center justify-between px-4 py-3 bg-gray-50 dark:bg-gray-800 rounded-xl hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors cursor-pointer"
             >
                <span className="flex items-center gap-2 text-gray-700 dark:text-gray-300">
                  <Upload size={18} /> Import Data
                </span>
             </label>
          </div>

          <button 
             onClick={downloadTemplate}
             className="text-xs text-primary-600 dark:text-primary-400 hover:underline text-left pl-2"
          >
             Download sample format template
          </button>

          {importStatus && (
             <div className={`text-sm p-3 rounded-lg ${importStatus.includes('Success') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                {importStatus}
             </div>
          )}
        </div>
      </section>
    </div>
  );
};

export default Settings;

import React, { useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { DataProvider, useData } from './contexts/DataContext';
import Layout from './components/Layout';
import Home from './pages/Home';
import Books from './pages/Books';
import Settings from './pages/Settings';

const ThemeController = () => {
  const { currentProfile } = useData();

  useEffect(() => {
    if (!currentProfile) return;

    const root = window.document.documentElement;
    const theme = currentProfile.themePreference;

    const applyTheme = (isDark: boolean) => {
      if (isDark) {
        root.classList.add('dark');
      } else {
        root.classList.remove('dark');
      }
    };

    if (theme === 'system') {
      const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
      applyTheme(mediaQuery.matches);

      const handler = (e: MediaQueryListEvent) => applyTheme(e.matches);
      mediaQuery.addEventListener('change', handler);
      return () => mediaQuery.removeEventListener('change', handler);
    } else {
      applyTheme(theme === 'dark');
    }
  }, [currentProfile?.themePreference]);

  return null;
};

const App: React.FC = () => {
  return (
    <DataProvider>
      <ThemeController />
      <HashRouter>
        <Routes>
          <Route path="/" element={<Layout />}>
            <Route index element={<Home />} />
            <Route path="books" element={<Books />} />
            <Route path="settings" element={<Settings />} />
            <Route path="*" element={<Navigate to="/" replace />} />
          </Route>
        </Routes>
      </HashRouter>
    </DataProvider>
  );
};

export default App;

