  name: string;
  isCurrent: boolean;
  themePreference: 'light' | 'dark' | 'system';
  syncFrequency: SyncFrequency;
  googleClientId?: string; // For Drive Integration
  googleAccessToken?: string;
  lastSyncedAt?: number;
}

export interface Book {
  id: string;
  profileId: string;
  name: string;
  currency: string;
  description?: string;
  color: string;
}

export interface Category {
  id: string;
  name: string;
  icon: string;
  color: string;
}

export interface Transaction {
  id: string;
  bookId: string;
  amount: number;
  type: TransactionType;
  categoryId: string;
  date: string; // ISO string including time
  note?: string;
  createdAt: number;
}

export interface DataContextType {
  profiles: Profile[];
  books: Book[];
  transactions: Transaction[];
  categories: Category[];
  currentProfile: Profile | null;

  // Actions
  addProfile: (name: string) => void;
  switchProfile: (id: string) => void;
  updateProfileSettings: (id: string, updates: Partial<Profile>) => void;

  addBook: (book: Omit<Book, 'id' | 'profileId'>) => void;
  deleteBook: (id: string) => void;

  addTransaction: (tx: Omit<Transaction, 'id' | 'createdAt'>) => void;
  deleteTransaction: (id: string) => void;

  importData: (csvText: string) => Promise<{ success: boolean; message: string }>;
  exportData: () => void;
  downloadTemplate: () => void;

  // Drive
  initGoogleDrive: (clientId: string) => Promise<void>;
  signInToGoogle: () => Promise<void>;
  signOutFromGoogle: () => Promise<void>;
  syncWithDrive: () => Promise<void>;
  isGoogleReady: boolean;
}

// Simple wrapper for Google Drive API interactions
// Requires "https://apis.google.com/js/api.js" and "https://accounts.google.com/gsi/client" loaded in index.html

declare const gapi: any;
declare const google: any;

const DISCOVERY_DOC = 'https://www.googleapis.com/discovery/v1/apis/drive/v3/rest';
const SCOPES = 'https://www.googleapis.com/auth/drive.file';

let tokenClient: any;
let gapiInited = false;
let gisInited = false;

export const initGapiClient = async () => {
  await new Promise<void>((resolve, reject) => {
    gapi.load('client', { callback: resolve, onerror: reject });
  });
  await gapi.client.init({
    discoveryDocs: [DISCOVERY_DOC],
  });
  gapiInited = true;
};

export const initGisClient = (clientId: string, callback: (resp: any) => void) => {
  tokenClient = google.accounts.oauth2.initTokenClient({
    client_id: clientId,
    scope: SCOPES,
    callback: async (resp: any) => {
      if (resp.error !== undefined) {
        throw (resp);
      }
      callback(resp);
    },
  });
  gisInited = true;
};

export const requestAccessToken = () => {
  if (!tokenClient) throw new Error("Token client not initialized");
  tokenClient.requestAccessToken({ prompt: 'consent' });
};

export const setAccessToken = (token: string) => {
  if(gapi && gapi.client) {
      gapi.client.setToken({ access_token: token });
  }
};

export const uploadFile = async (fileName: string, content: string, mimeType = 'application/json') => {
  try {
    const file = new Blob([content], { type: mimeType });
    const metadata = {
      name: fileName,
      mimeType: mimeType,
    };

    const accessToken = gapi.client.getToken().access_token;
    const form = new FormData();
    form.append('metadata', new Blob([JSON.stringify(metadata)], { type: 'application/json' }));
    form.append('file', file);

    const res = await fetch('https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart', {
      method: 'POST',
      headers: new Headers({ 'Authorization': 'Bearer ' + accessToken }),
      body: form,
    });
    return await res.json();
  } catch (error) {
    console.error('Error uploading file:', error);
    throw error;
  }
};

export const findFile = async (fileName: string) => {
    try {
        const response = await gapi.client.drive.files.list({
            q: `name = '${fileName}' and trashed = false`,
            fields: 'files(id, name, createdTime)',
            spaces: 'drive',
        });
        const files = response.result.files;
        return files && files.length > 0 ? files[0] : null;
    } catch (err) {
        console.error("Error finding file", err);
        return null;
    }
}

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Profile, Book, Transaction, Category, DataContextType, 
  SyncFrequency, TransactionType 
} from '../types';
import { DEFAULT_CATEGORIES } from '../constants';
import { generateCSV, parseCSV, SAMPLE_CSV } from '../utils/csvHelper';
import * as driveService from '../utils/driveService';

const DataContext = createContext<DataContextType | undefined>(undefined);

const STORAGE_KEY = 'expenSync_v1';
const DRIVE_FILE_NAME = 'expenSync_backup.json';

const INITIAL_PROFILE: Profile = {
  id: 'default_profile',
  name: 'Main User',
  isCurrent: true,
  themePreference: 'system',
  syncFrequency: SyncFrequency.OFF
};

const INITIAL_BOOK: Book = {
  id: 'default_book',
  profileId: 'default_profile',
  name: 'Personal Wallet',
  currency: 'USD',
  color: 'bg-blue-500'
};

export const DataProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [profiles, setProfiles] = useState<Profile[]>([]);
  const [books, setBooks] = useState<Book[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isGoogleReady, setIsGoogleReady] = useState(false);

  // Load initial data
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      const parsed = JSON.parse(saved);
      setProfiles(parsed.profiles || [INITIAL_PROFILE]);
      setBooks(parsed.books || [INITIAL_BOOK]);
      setTransactions(parsed.transactions || []);

      // Attempt to re-init Google Drive if a token/client ID exists
      const current = (parsed.profiles as Profile[])?.find(p => p.isCurrent);
      if (current?.googleClientId && window.gapi) {
        initGoogleDrive(current.googleClientId);
      }
    } else {
      setProfiles([INITIAL_PROFILE]);
      setBooks([INITIAL_BOOK]);
      setTransactions([]);
    }
  }, []);

  // Save on change
  useEffect(() => {
    if (profiles.length > 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ profiles, books, transactions }));
    }
  }, [profiles, books, transactions]);

  const currentProfile = profiles.find(p => p.isCurrent) || profiles[0] || null;

  // --- Actions ---

  const addProfile = (name: string) => {
    const newProfile: Profile = {
      id: uuidv4(),
      name,
      isCurrent: true,
      themePreference: 'system',
      syncFrequency: SyncFrequency.OFF
    };

    const updatedProfiles = profiles.map(p => ({ ...p, isCurrent: false }));
    setProfiles([...updatedProfiles, newProfile]);

    const newBook: Book = {
      id: uuidv4(),
      profileId: newProfile.id,
      name: 'My Wallet',
      currency: 'USD',
      color: 'bg-emerald-500'
    };
    setBooks(prev => [...prev, newBook]);
  };

  const switchProfile = (id: string) => {
    setProfiles(prev => prev.map(p => ({
      ...p,
      isCurrent: p.id === id
    })));
  };

  const updateProfileSettings = (id: string, updates: Partial<Profile>) => {
    setProfiles(prev => prev.map(p => p.id === id ? { ...p, ...updates } : p));
  };

  const addBook = (bookData: Omit<Book, 'id' | 'profileId'>) => {
    if (!currentProfile) return;
    const newBook: Book = {
      ...bookData,
      id: uuidv4(),
      profileId: currentProfile.id
    };
    setBooks(prev => [...prev, newBook]);
  };

  const deleteBook = (id: string) => {
    setBooks(prev => prev.filter(b => b.id !== id));
    setTransactions(prev => prev.filter(t => t.bookId !== id));
  };

  const addTransaction = (txData: Omit<Transaction, 'id' | 'createdAt'>) => {
    const newTx: Transaction = {
      ...txData,
      id: uuidv4(),
      createdAt: Date.now()
    };
    setTransactions(prev => [newTx, ...prev]);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  // --- Import / Export ---

  const downloadTemplate = useCallback(() => {
    const blob = new Blob([SAMPLE_CSV], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'expenses_template.csv';
    a.click();
    window.URL.revokeObjectURL(url);
  }, []);

  const exportData = useCallback(() => {
    if (!currentProfile) return;
    const profileBookIds = books.filter(b => b.profileId === currentProfile.id).map(b => b.id);
    const profileTransactions = transactions.filter(t => profileBookIds.includes(t.bookId));

    const csv = generateCSV(profileTransactions, books, DEFAULT_CATEGORIES);
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `ET_${currentProfile.name.replace(/\s+/g, '_')}_${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
    window.URL.revokeObjectURL(url);
  }, [currentProfile, books, transactions]);

  const importData = async (csvText: string): Promise<{ success: boolean; message: string }> => {
    try {
      if (!currentProfile) throw new Error("No profile selected");
      const rows = parseCSV(csvText);
      const newTransactions: Transaction[] = [];
      let importedCount = 0;

      for (const row of rows) {
        let book = books.find(b => b.name === row['Book'] && b.profileId === currentProfile.id);
        if (!book) {
            const newBookId = uuidv4();
            const newBook: Book = {
                id: newBookId,
                profileId: currentProfile.id,
                name: row['Book'] || 'Imported Book',
                currency: 'USD',
                color: 'bg-gray-500'
            };
            setBooks(prev => [...prev, newBook]);
            book = newBook;
        }

        const cat = DEFAULT_CATEGORIES.find(c => c.name === row['Category']) || DEFAULT_CATEGORIES[6];

        if (row['Amount'] && row['Date']) {
            newTransactions.push({
                id: uuidv4(),
                bookId: book.id,
                amount: parseFloat(row['Amount']),
                type: row['Type'] === 'INCOME' ? TransactionType.INCOME : TransactionType.EXPENSE,
                categoryId: cat.id,
                date: row['Date'], // Assuming ISO date from CSV for now
                note: row['Note'] || '',
                createdAt: Date.now()
            });
            importedCount++;
        }
      }
      setTransactions(prev => [...newTransactions, ...prev]);
      return { success: true, message: `Successfully imported ${importedCount} transactions.` };
    } catch (e: any) {
      return { success: false, message: e.message || "Failed to import CSV" };
    }
  };

  // --- Google Drive Integration ---

  const initGoogleDrive = async (clientId: string) => {
    try {
      if (!window.gapi || !window.google) {
        console.warn("Google API scripts not loaded");
        return;
      }

      await driveService.initGapiClient();

      driveService.initGisClient(clientId, (response) => {
        if(response.access_token && currentProfile) {
           updateProfileSettings(currentProfile.id, { googleAccessToken: response.access_token });
           driveService.setAccessToken(response.access_token);
        }
      });
      setIsGoogleReady(true);
    } catch (e) {
      console.error("Failed to init Google Drive", e);
    }
  };

  const signInToGoogle = async () => {
     if(!isGoogleReady) return;
     driveService.requestAccessToken();
  };

  const signOutFromGoogle = async () => {
    if(currentProfile) {
      updateProfileSettings(currentProfile.id, { googleAccessToken: undefined });
      // In a real app we might revoke token, but for now just clearing state
    }
  };

  const syncWithDrive = async () => {
    if (!currentProfile?.googleAccessToken) {
       await signInToGoogle();
       return; 
    }

    // Simple Backup Strategy: Upload current state as JSON
    const data = JSON.stringify({
       profile: currentProfile,
       books: books.filter(b => b.profileId === currentProfile.id),
       transactions: transactions.filter(t => books.find(b => b.id === t.bookId)?.profileId === currentProfile.id)
    });

    try {
       await driveService.uploadFile(DRIVE_FILE_NAME, data);
       updateProfileSettings(currentProfile.id, { lastSyncedAt: Date.now() });
       alert("Sync successful!");
    } catch(e) {
       console.error(e);
       alert("Sync failed. Check console.");
    }
  };

  const value = {
    profiles,
    books,
    transactions,
    categories: DEFAULT_CATEGORIES,
    currentProfile,
    addProfile,
    switchProfile,
    updateProfileSettings,
    addBook,
    deleteBook,
    addTransaction,
    deleteTransaction,
    importData,
    exportData,
    downloadTemplate,
    initGoogleDrive,
    signInToGoogle,
    signOutFromGoogle,
    syncWithDrive,
    isGoogleReady
  };

  return <DataContext.Provider value={value}>{children}</DataContext.Provider>;
};

export const useData = () => {
  const context = useContext(DataContext);
  if (!context) throw new Error("useData must be used within DataProvider");
  return context;
};

