import React, { useState } from 'react';
import { useData } from '../contexts/DataContext';
import { Plus, FolderOpen, ArrowLeft, Trash2 } from 'lucide-react';
import TransactionModal from '../components/TransactionModal';
import { TransactionType } from '../types';
import { CURRENCIES } from '../constants';

const Books: React.FC = () => {
  const { currentProfile, books, transactions, addBook, deleteBook, deleteTransaction, categories } = useData();
  const [selectedBookId, setSelectedBookId] = useState<string | null>(null);
  const [isAddTxOpen, setIsAddTxOpen] = useState(false);

  // For adding a new book
  const [isAddBookMode, setIsAddBookMode] = useState(false);
  const [newBookName, setNewBookName] = useState('');
  const [newBookCurrency, setNewBookCurrency] = useState('USD');

  const myBooks = books.filter(b => b.profileId === currentProfile?.id);

  const handleAddBook = (e: React.FormEvent) => {
    e.preventDefault();
    if (newBookName) {
      addBook({ name: newBookName, currency: newBookCurrency, color: 'bg-blue-500' });
      setIsAddBookMode(false);
      setNewBookName('');
    }
  };

  const selectedBook = books.find(b => b.id === selectedBookId);
  const bookTransactions = transactions
    .filter(t => t.bookId === selectedBookId)
    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  // Book Detail View
  if (selectedBookId && selectedBook) {
    const total = bookTransactions.reduce((acc, t) => {
        return t.type === TransactionType.INCOME ? acc + t.amount : acc - t.amount;
    }, 0);

    const currencySymbol = CURRENCIES.find(c => c.code === selectedBook.currency)?.symbol || '$';

    return (
      <div className="animate-fade-in">
        <div className="flex items-center gap-2 mb-6">
          <button 
            onClick={() => setSelectedBookId(null)} 
            className="p-2 hover:bg-gray-200 dark:hover:bg-gray-800 rounded-full transition-colors"
          >
            <ArrowLeft size={24} className="text-gray-700 dark:text-gray-300" />
          </button>
          <h2 className="text-xl font-bold text-gray-900 dark:text-white">{selectedBook.name}</h2>
          <span className="ml-auto text-sm font-bold px-3 py-1 bg-gray-100 dark:bg-gray-800 rounded-lg text-gray-600 dark:text-gray-300">
             {selectedBook.currency} {total.toFixed(2)}
          </span>
        </div>

        {/* Action Bar */}
        <div className="flex gap-2 mb-6">
           <button 
             onClick={() => setIsAddTxOpen(true)}
             className="flex-1 bg-primary-600 hover:bg-primary-700 text-white font-semibold py-3 px-4 rounded-xl flex items-center justify-center gap-2 shadow-sm"
           >
             <Plus size={20} /> Add Expense / Income
           </button>
        </div>

        {/* List */}
        <div className="space-y-3">
           {bookTransactions.length === 0 ? (
               <div className="text-center py-10 text-gray-400 bg-white dark:bg-cardbg rounded-xl border border-dashed border-gray-300 dark:border-gray-700">
                  No transactions in this book yet.
               </div>
           ) : (
               bookTransactions.map(tx => {
                 const cat = categories.find(c => c.id === tx.categoryId);
                 const dateObj = new Date(tx.date);
                 return (
                    <div key={tx.id} className="bg-white dark:bg-cardbg p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-800 flex justify-between items-center group">
                        <div className="flex items-center gap-3">
                            <div className={`p-2 rounded-lg ${cat?.color} bg-opacity-10 dark:bg-opacity-20`}>
                                {/* Placeholder icon */}
                                <div className="w-4 h-4 rounded-full bg-current opacity-50"></div>
                            </div>
                            <div>
                                <p className="font-medium text-gray-900 dark:text-gray-100">{cat?.name}</p>
                                <p className="text-xs text-gray-500">
                                  {dateObj.toLocaleDateString()} {dateObj.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                  {tx.note && ` • ${tx.note}`}
                                </p>
                            </div>
                        </div>
                        <div className="flex items-center gap-4">
                            <span className={`font-bold ${tx.type === TransactionType.INCOME ? 'text-green-600' : 'text-gray-900 dark:text-white'}`}>
                                {tx.type === TransactionType.INCOME ? '+' : '-'}{currencySymbol}{tx.amount.toFixed(2)}
                            </span>
                            <button 
                                onClick={() => deleteTransaction(tx.id)}
                                className="text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                            >
                                <Trash2 size={16} />
                            </button>
                        </div>
                    </div>
                 );
               })
           )}
        </div>

        <div className="mt-8 pt-8 border-t border-gray-200 dark:border-gray-700 flex justify-center">
             <button 
                onClick={() => {
                   if(confirm('Are you sure you want to delete this book and all its transactions?')) {
                      deleteBook(selectedBookId);
                      setSelectedBookId(null);
                   }
                }}
                className="text-red-500 text-sm hover:underline"
             >
                Delete Book
             </button>
        </div>

        <TransactionModal 
            isOpen={isAddTxOpen} 
            onClose={() => setIsAddTxOpen(false)} 
            preSelectedBookId={selectedBookId}
        />
      </div>
    );
  }

  // All Books List
  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
         <h2 className="text-2xl font-bold text-gray-900 dark:text-white">My Books</h2>
         <button 
           onClick={() => setIsAddBookMode(true)}
           className="p-2 bg-gray-100 dark:bg-gray-800 text-primary-600 rounded-full hover:bg-primary-50 dark:hover:bg-gray-700 transition-colors"
         >
           <Plus size={24} />
         </button>
      </div>

      {isAddBookMode && (
          <form onSubmit={handleAddBook} className="bg-white dark:bg-cardbg p-4 rounded-2xl shadow-lg border border-primary-100 dark:border-primary-900 animate-in fade-in slide-in-from-top-2">
              <h3 className="font-semibold mb-3 dark:text-white">Create New Book</h3>
              <div className="space-y-3">
                  <input 
                    type="text" 
                    placeholder="Book Name (e.g., Business)" 
                    value={newBookName}
                    onChange={e => setNewBookName(e.target.value)}
                    className="w-full bg-gray-50 dark:bg-gray-800 border-none rounded-xl px-4 py-2 dark:text-white focus:ring-2 focus:ring-primary-500"
                    autoFocus
                  />

                  {/* Currency Dropdown with Flags */}
                  <div className="relative">
                      <select 
                         value={newBookCurrency}
                         onChange={e => setNewBookCurrency(e.target.value)}
                         className="w-full bg-gray-50 dark:bg-gray-800 border-none rounded-xl px-4 py-2 dark:text-white appearance-none"
                      >
                          {CURRENCIES.map(c => (
                              <option key={c.code} value={c.code}>
                                  {c.flag} {c.code} - {c.name}
                              </option>
                          ))}
                      </select>
                      <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400">▼</div>
                  </div>

                  <div className="flex gap-2 pt-2">
                      <button type="button" onClick={() => setIsAddBookMode(false)} className="flex-1 py-2 text-gray-500 hover:bg-gray-50 rounded-lg">Cancel</button>
                      <button type="submit" className="flex-1 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700">Create</button>
                  </div>
              </div>
          </form>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {myBooks.map(book => {
            const balance = transactions
                .filter(t => t.bookId === book.id)
                .reduce((acc, t) => t.type === TransactionType.INCOME ? acc + t.amount : acc - t.amount, 0);

            const symbol = CURRENCIES.find(c => c.code === book.currency)?.symbol || '$';

            return (
                <button 
                    key={book.id}
                    onClick={() => setSelectedBookId(book.id)}
                    className="bg-white dark:bg-cardbg p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-800 hover:shadow-md transition-shadow text-left group"
                >
                    <div className="flex justify-between items-start mb-4">
                        <div className={`p-3 rounded-xl ${book.color} bg-opacity-10 text-primary-600 dark:text-primary-400`}>
                            <FolderOpen size={24} />
                        </div>
                        <span className="text-xs font-semibold px-2 py-1 rounded bg-gray-50 dark:bg-gray-700 text-gray-500 dark:text-gray-300">
                            {book.currency}
                        </span>
                    </div>
                    <h3 className="font-bold text-lg text-gray-900 dark:text-white group-hover:text-primary-600 transition-colors">{book.name}</h3>
                    <p className="text-gray-500 dark:text-gray-400 text-sm mt-1">Balance: {symbol}{balance.toFixed(2)}</p>
                </button>
            );
        })}
      </div>
    </div>
  );
};

export default Books;

import React, { useState, useMemo } from 'react';
import { useData } from '../contexts/DataContext';
import { Plus, Wallet, TrendingUp, TrendingDown, ArrowRight } from 'lucide-react';
import TransactionModal from '../components/TransactionModal';
import { TransactionType } from '../types';
import { 
  PieChart, Pie, Cell, ResponsiveContainer, Tooltip, 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Legend,
  AreaChart, Area
} from 'recharts';

const Home: React.FC = () => {
  const { currentProfile, books, transactions, categories } = useData();
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Derive data
  const profileBookIds = useMemo(() => 
    books.filter(b => b.profileId === currentProfile?.id).map(b => b.id), 
    [books, currentProfile]
  );

  const profileTransactions = useMemo(() => 
    transactions
      .filter(t => profileBookIds.includes(t.bookId))
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()),
    [transactions, profileBookIds]
  );

  const totalIncome = useMemo(() => 
    profileTransactions
      .filter(t => t.type === TransactionType.INCOME)
      .reduce((sum, t) => sum + t.amount, 0),
    [profileTransactions]
  );

  const totalExpense = useMemo(() => 
    profileTransactions
      .filter(t => t.type === TransactionType.EXPENSE)
      .reduce((sum, t) => sum + t.amount, 0),
    [profileTransactions]
  );

  // Data for Pie Chart (Category Breakdown)
  const pieData = useMemo(() => {
    const data: {[key: string]: number} = {};
    profileTransactions
      .filter(t => t.type === TransactionType.EXPENSE)
      .forEach(t => {
        const catName = categories.find(c => c.id === t.categoryId)?.name || 'Other';
        data[catName] = (data[catName] || 0) + t.amount;
      });
    return Object.entries(data).map(([name, value]) => ({ name, value }));
  }, [profileTransactions, categories]);

  // Data for Bar Chart (Daily Spending/Income - Last 7 days)
  const barData = useMemo(() => {
    const last7Days = [...Array(7)].map((_, i) => {
        const d = new Date();
        d.setDate(d.getDate() - i);
        return d.toISOString().split('T')[0];
    }).reverse();

    return last7Days.map(date => {
        const dayTxs = profileTransactions.filter(t => t.date.startsWith(date));
        return {
            date: new Date(date).toLocaleDateString(undefined, {weekday: 'short'}),
            income: dayTxs.filter(t => t.type === TransactionType.INCOME).reduce((sum, t) => sum + t.amount, 0),
            expense: dayTxs.filter(t => t.type === TransactionType.EXPENSE).reduce((sum, t) => sum + t.amount, 0)
        };
    });
  }, [profileTransactions]);

  const COLORS = ['#0ea5e9', '#ef4444', '#eab308', '#22c55e', '#a855f7', '#ec4899', '#64748b'];
  const getBookName = (id: string) => books.find(b => b.id === id)?.name || 'Unknown';
  const getCatName = (id: string) => categories.find(c => c.id === id)?.name || 'Other';

  return (
    <div className="space-y-6">
      {/* 1-Stop Add Action */}
      <div className="bg-gradient-to-r from-primary-600 to-primary-800 rounded-2xl p-6 text-white shadow-lg shadow-primary-500/20 relative overflow-hidden">
        <div className="relative z-10">
          <p className="text-primary-100 text-sm font-medium mb-1">Total Balance</p>
          <h2 className="text-3xl font-bold mb-6">${(totalIncome - totalExpense).toFixed(2)}</h2>

          <button 
            onClick={() => setIsModalOpen(true)}
            className="bg-white text-primary-700 hover:bg-gray-50 font-semibold py-3 px-6 rounded-xl flex items-center gap-2 transition-transform active:scale-95 shadow-sm"
          >
            <Plus size={20} />
            Quick Add
          </button>
        </div>

        {/* Decorative Circle */}
        <div className="absolute -right-10 -bottom-16 w-48 h-48 bg-white/10 rounded-full blur-2xl"></div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-2 gap-4">
        <div className="bg-white dark:bg-cardbg p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-800">
          <div className="flex items-center gap-2 mb-2">
            <div className="p-2 bg-green-100 dark:bg-green-900/30 rounded-full text-green-600 dark:text-green-400">
              <TrendingUp size={18} />
            </div>
            <span className="text-sm text-gray-500 dark:text-gray-400">Income</span>
          </div>
          <p className="text-lg font-bold text-gray-900 dark:text-white">${totalIncome.toFixed(2)}</p>
        </div>
        <div className="bg-white dark:bg-cardbg p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-800">
          <div className="flex items-center gap-2 mb-2">
             <div className="p-2 bg-red-100 dark:bg-red-900/30 rounded-full text-red-600 dark:text-red-400">
              <TrendingDown size={18} />
            </div>
            <span className="text-sm text-gray-500 dark:text-gray-400">Expenses</span>
          </div>
          <p className="text-lg font-bold text-gray-900 dark:text-white">${totalExpense.toFixed(2)}</p>
        </div>
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Bar Chart - Daily Trends */}
          <div className="bg-white dark:bg-cardbg p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-800">
             <h3 className="font-semibold text-gray-800 dark:text-gray-200 mb-4">Last 7 Days</h3>
             <div className="h-64 w-full">
               <ResponsiveContainer width="100%" height="100%">
                 <BarChart data={barData}>
                    <CartesianGrid strokeDasharray="3 3" opacity={0.1} />
                    <XAxis dataKey="date" fontSize={12} stroke="#888" />
                    <YAxis fontSize={12} stroke="#888" />
                    <Tooltip 
                        contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff' }}
                    />
                    <Legend />
                    <Bar dataKey="income" fill="#22c55e" radius={[4, 4, 0, 0]} name="Income" />
                    <Bar dataKey="expense" fill="#ef4444" radius={[4, 4, 0, 0]} name="Expense" />
                 </BarChart>
               </ResponsiveContainer>
             </div>
          </div>

          {/* Pie Chart - Categories */}
          {pieData.length > 0 && (
             <div className="bg-white dark:bg-cardbg p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-800">
                <h3 className="font-semibold text-gray-800 dark:text-gray-200 mb-4">Spending by Category</h3>
                <div className="h-64 w-full">
                  <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                      <Pie
                        data={pieData}
                        innerRadius={60}
                        outerRadius={80}
                        paddingAngle={5}
                        dataKey="value"
                      >
                        {pieData.map((entry, index) => (
                          <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                      </Pie>
                      <Tooltip 
                        contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff' }}
                      />
                      <Legend />
                    </PieChart>
                  </ResponsiveContainer>
                </div>
             </div>
          )}
      </div>

      {/* Recent Transactions */}
      <div>
        <div className="flex justify-between items-end mb-3 px-1">
           <h3 className="font-semibold text-lg text-gray-800 dark:text-gray-200">Recent Transactions</h3>
        </div>
        <div className="bg-white dark:bg-cardbg rounded-2xl shadow-sm border border-gray-100 dark:border-gray-800 overflow-hidden">
           {profileTransactions.length === 0 ? (
             <div className="p-8 text-center text-gray-400">No transactions yet.</div>
           ) : (
             <div className="divide-y divide-gray-100 dark:divide-gray-800">
               {profileTransactions.slice(0, 5).map(tx => {
                 const dateObj = new Date(tx.date);
                 return (
                 <div key={tx.id} className="p-4 flex items-center justify-between hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors">
                    <div className="flex items-center gap-3">
                       <div className={`w-10 h-10 rounded-full flex items-center justify-center ${tx.type === TransactionType.INCOME ? 'bg-green-100 text-green-600 dark:bg-green-900/20' : 'bg-red-100 text-red-600 dark:bg-red-900/20'}`}>
                          <Wallet size={18} />
                       </div>
                       <div>
                          <p className="font-medium text-gray-900 dark:text-gray-100">{getCatName(tx.categoryId)}</p>
                          <p className="text-xs text-gray-500">
                             {getBookName(tx.bookId)} • {dateObj.toLocaleDateString()} {dateObj.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}
                          </p>
                       </div>
                    </div>
                    <span className={`font-bold ${tx.type === TransactionType.INCOME ? 'text-green-600' : 'text-gray-900 dark:text-white'}`}>
                      {tx.type === TransactionType.INCOME ? '+' : '-'}${tx.amount.toFixed(2)}
                    </span>
                 </div>
               )})}
             </div>
           )}
           {profileTransactions.length > 5 && (
             <div className="p-3 text-center border-t border-gray-100 dark:border-gray-800">
                <button className="text-sm font-medium text-primary-600 hover:text-primary-700 flex items-center justify-center gap-1 w-full">
                  View All <ArrowRight size={14} />
                </button>
             </div>
           )}
        </div>
      </div>

      <TransactionModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} />
    </div>
  );
};

export default Home;

import React, { useState, useRef, useEffect } from 'react';
import { useData } from '../contexts/DataContext';
import { Moon, Sun, Monitor, Cloud, User, Download, Upload, FileText, CheckCircle, AlertTriangle } from 'lucide-react';
import { SyncFrequency } from '../types';

const Settings: React.FC = () => {
  const { 
    profiles, 
    currentProfile, 
    updateProfileSettings, 
    switchProfile, 
    addProfile,
    exportData,
    importData,
    downloadTemplate,
    initGoogleDrive,
    signInToGoogle,
    signOutFromGoogle,
    syncWithDrive
  } = useData();

  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncTime, setLastSyncTime] = useState<string | null>(null);
  const [newProfileName, setNewProfileName] = useState('');
  const [importStatus, setImportStatus] = useState<string>('');
  const [clientId, setClientId] = useState(currentProfile?.googleClientId || '');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if(currentProfile?.googleClientId) {
      setClientId(currentProfile.googleClientId);
    }
  }, [currentProfile]);

  const handleThemeChange = (theme: 'light' | 'dark' | 'system') => {
    if (currentProfile) {
      updateProfileSettings(currentProfile.id, { themePreference: theme });
      // Apply class immediately for UX
      if (theme === 'dark' || (theme === 'system' && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
        document.documentElement.classList.add('dark');
      } else {
        document.documentElement.classList.remove('dark');
      }
    }
  };

  const handleSyncNow = async () => {
    setIsSyncing(true);
    await syncWithDrive();
    setIsSyncing(false);
    setLastSyncTime(new Date().toLocaleTimeString());
  };

  const handleCreateProfile = (e: React.FormEvent) => {
    e.preventDefault();
    if(newProfileName.trim()){
      addProfile(newProfileName);
      setNewProfileName('');
    }
  }

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const text = event.target?.result as string;
      const result = await importData(text);
      setImportStatus(result.message);
      setTimeout(() => setImportStatus(''), 5000);
    };
    reader.readAsText(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleSaveClientId = () => {
    if(currentProfile && clientId) {
      updateProfileSettings(currentProfile.id, { googleClientId: clientId });
      initGoogleDrive(clientId);
      alert("Client ID Saved. You can now Sign In.");
    }
  };

  if (!currentProfile) return null;

  return (
    <div className="space-y-8 animate-fade-in">
      <h2 className="text-2xl font-bold text-gray-900 dark:text-white">Settings</h2>

      {/* Profile Section */}
      <section className="bg-white dark:bg-cardbg rounded-2xl p-6 shadow-sm border border-gray-100 dark:border-gray-800">
        <h3 className="text-lg font-semibold mb-4 flex items-center gap-2 dark:text-white">
          <User className="text-primary-500" size={20} /> Profiles
        </h3>

        <div className="flex gap-2 overflow-x-auto pb-4 mb-4 no-scrollbar">
          {profiles.map(p => (
            <button
              key={p.id}
              onClick={() => switchProfile(p.id)}
              className={`flex-shrink-0 px-5 py-2 rounded-full border text-sm font-medium transition-colors ${p.id === currentProfile.id ? 'bg-primary-600 border-primary-600 text-white' : 'bg-gray-50 dark:bg-gray-800 border-gray-200 dark:border-gray-700 text-gray-600 dark:text-gray-300'}`}
            >
              {p.name}
            </button>
          ))}
        </div>

        <form onSubmit={handleCreateProfile} className="flex gap-2">
           <input 
             type="text" 
             value={newProfileName}
             onChange={e => setNewProfileName(e.target.value)}
             placeholder="New profile name..."
             className="flex-1 bg-gray-50 dark:bg-gray-800 border-none rounded-xl px-4 py-2 dark:text-white text-sm focus:ring-2 focus:ring-primary-500"
           />
           <button type="submit" disabled={!newProfileName} className="bg-gray-900 dark:bg-white dark:text-black text-white px-4 py-2 rounded-xl text-sm font-medium disabled:opacity-50">Create</button>
        </form>
      </section>

      {/* Appearance */}
      <section className="bg-white dark:bg-cardbg rounded-2xl p-6 shadow-sm border border-gray-100 dark:border-gray-800">
         <h3 className="text-lg font-semibold mb-4 flex items-center gap-2 dark:text-white">
          <Monitor className="text-purple-500" size={20} /> Appearance
        </h3>
        <div className="grid grid-cols-3 gap-3">
          {(['light', 'dark', 'system'] as const).map((mode) => (
            <button
              key={mode}
              onClick={() => handleThemeChange(mode)}
              className={`flex flex-col items-center justify-center p-3 rounded-xl border-2 transition-all ${currentProfile.themePreference === mode ? 'border-primary-500 bg-primary-50 dark:bg-primary-900/20' : 'border-transparent bg-gray-50 dark:bg-gray-800'}`}
            >
               {mode === 'light' && <Sun size={24} className="mb-2 text-orange-500" />}
               {mode === 'dark' && <Moon size={24} className="mb-2 text-indigo-500" />}
               {mode === 'system' && <Monitor size={24} className="mb-2 text-gray-500" />}
               <span className="capitalize text-sm font-medium dark:text-gray-300">{mode}</span>
            </button>
          ))}
        </div>
      </section>

      {/* Sync */}
      <section className="bg-white dark:bg-cardbg rounded-2xl p-6 shadow-sm border border-gray-100 dark:border-gray-800">
         <h3 className="text-lg font-semibold mb-4 flex items-center gap-2 dark:text-white">
          <Cloud className="text-blue-500" size={20} /> Google Drive Backup
        </h3>

        <div className="mb-4 p-4 bg-blue-50 dark:bg-blue-900/10 rounded-xl text-sm text-blue-700 dark:text-blue-300">
