                      <button type="submit" className="flex-1 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700">Create</button>
                  </div>
              </div>
          </form>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {myBooks.map(book => {
            const balance = transactions
                .filter(t => t.bookId === book.id)
                .reduce((acc, t) => t.type === TransactionType.INCOME ? acc + t.amount : acc - t.amount, 0);

            const symbol = CURRENCIES.find(c => c.code === book.currency)?.symbol || '$';

            return (
                <button 
                    key={book.id}
                    onClick={() => setSelectedBookId(book.id)}
                    className="bg-white dark:bg-cardbg p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-800 hover:shadow-md transition-shadow text-left group"
                >
                    <div className="flex justify-between items-start mb-4">
                        <div className={`p-3 rounded-xl ${book.color} bg-opacity-10 text-primary-600 dark:text-primary-400`}>
                            <FolderOpen size={24} />
                        </div>
                        <span className="text-xs font-semibold px-2 py-1 rounded bg-gray-50 dark:bg-gray-700 text-gray-500 dark:text-gray-300">
                            {book.currency}
                        </span>
                    </div>
                    <h3 className="font-bold text-lg text-gray-900 dark:text-white group-hover:text-primary-600 transition-colors">{book.name}</h3>
                    <p className="text-gray-500 dark:text-gray-400 text-sm mt-1">Balance: {symbol}{balance.toFixed(2)}</p>
                </button>
            );
        })}
      </div>
    </div>
  );
};

export default Books;

export enum TransactionType {
  INCOME = 'INCOME',
  EXPENSE = 'EXPENSE',
}

export enum SyncFrequency {
  IMMEDIATE = 'IMMEDIATE',
  DAILY = 'DAILY',
  MONTHLY = 'MONTHLY',
  OFF = 'OFF',
}

export interface Profile {
  id: string;
  name: string;
  isCurrent: boolean;
  themePreference: 'light' | 'dark' | 'system';
  isPrivacyMode: boolean; // New field
  syncFrequency: SyncFrequency;
  googleClientId?: string;
  googleAccessToken?: string;
  lastSyncedAt?: number;
}

export interface Book {
  id: string;
  profileId: string;
  name: string;
  currency: string;
  description?: string;
  color: string;
}

export interface Category {
  id: string;
  name: string;
  icon: string;
  color: string;
}

export interface Transaction {
  id: string;
  bookId: string;
  amount: number;
  type: TransactionType;
  categoryId: string;
  date: string;
  note?: string;
  createdAt: number;
}

export interface DataContextType {
  profiles: Profile[];
  books: Book[];
  transactions: Transaction[];
  categories: Category[];
  currentProfile: Profile | null;

  // Actions
  addProfile: (name: string) => void;
  switchProfile: (id: string) => void;
  updateProfileSettings: (id: string, updates: Partial<Profile>) => void;
  togglePrivacyMode: () => void; // New action

  addBook: (book: Omit<Book, 'id' | 'profileId'>) => void;
  updateBook: (id: string, updates: Partial<Book>) => void; // New action
  deleteBook: (id: string) => void;

  addTransaction: (tx: Omit<Transaction, 'id' | 'createdAt'>) => void;
  updateTransaction: (id: string, updates: Partial<Transaction>) => void; // New action
  deleteTransaction: (id: string) => void;

  importData: (csvText: string) => Promise<{ success: boolean; message: string }>;
  exportData: () => void;
  downloadTemplate: () => void;

  // Drive
  initGoogleDrive: (clientId: string) => Promise<void>;
  signInToGoogle: () => Promise<void>;
  signOutFromGoogle: () => Promise<void>;
  syncWithDrive: () => Promise<void>;
  isGoogleReady: boolean;
}

import React, { createContext, useContext, useState, useCallback } from 'react';
import { X, CheckCircle, AlertCircle, Info } from 'lucide-react';

type ToastType = 'success' | 'error' | 'info';

interface Toast {
  id: string;
  message: string;
  type: ToastType;
}

interface ToastContextType {
  showToast: (message: string, type?: ToastType) => void;
}

const ToastContext = createContext<ToastContextType | undefined>(undefined);

export const ToastProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [toasts, setToasts] = useState<Toast[]>([]);

  const showToast = useCallback((message: string, type: ToastType = 'info') => {
    const id = Math.random().toString(36).substr(2, 9);
    setToasts((prev) => [...prev, { id, message, type }]);

    setTimeout(() => {
      setToasts((prev) => prev.filter((t) => t.id !== id));
    }, 3000);
  }, []);

  const removeToast = (id: string) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  };

  return (
    <ToastContext.Provider value={{ showToast }}>
      {children}
      <div className="fixed top-4 left-1/2 transform -translate-x-1/2 z-[60] flex flex-col gap-2 w-full max-w-sm px-4">
        {toasts.map((toast) => (
          <div
            key={toast.id}
            className={`
              flex items-center gap-3 p-4 rounded-xl shadow-lg border animate-in slide-in-from-top-2 fade-in
              ${toast.type === 'success' ? 'bg-white dark:bg-cardbg border-green-500 text-green-600' : ''}
              ${toast.type === 'error' ? 'bg-white dark:bg-cardbg border-red-500 text-red-600' : ''}
              ${toast.type === 'info' ? 'bg-white dark:bg-cardbg border-blue-500 text-blue-600' : ''}
            `}
          >
            {toast.type === 'success' && <CheckCircle size={20} />}
            {toast.type === 'error' && <AlertCircle size={20} />}
            {toast.type === 'info' && <Info size={20} />}
            <p className="flex-1 text-sm font-medium text-gray-800 dark:text-gray-200">{toast.message}</p>
            <button onClick={() => removeToast(toast.id)} className="text-gray-400 hover:text-gray-600">
              <X size={16} />
            </button>
          </div>
        ))}
      </div>
    </ToastContext.Provider>
  );
};

export const useToast = () => {
  const context = useContext(ToastContext);
  if (!context) throw new Error('useToast must be used within a ToastProvider');
  return context;
};

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Profile, Book, Transaction, Category, DataContextType, 
  SyncFrequency, TransactionType 
} from '../types';
import { DEFAULT_CATEGORIES } from '../constants';
import { generateCSV, parseCSV, SAMPLE_CSV } from '../utils/csvHelper';
import * as driveService from '../utils/driveService';

// Extend Window interface to include gapi and google
declare global {
  interface Window {
    gapi: any;
    google: any;
  }
}

const DataContext = createContext<DataContextType | undefined>(undefined);

const STORAGE_KEY = 'expenSync_v1';
const DRIVE_FILE_NAME = 'expenSync_backup.json';

const INITIAL_PROFILE: Profile = {
  id: 'default_profile',
  name: 'Main User',
  isCurrent: true,
  themePreference: 'system',
  isPrivacyMode: false,
  syncFrequency: SyncFrequency.OFF
};

const INITIAL_BOOK: Book = {
  id: 'default_book',
  profileId: 'default_profile',
  name: 'Personal Wallet',
  currency: 'USD',
  color: 'bg-blue-500'
};

export const DataProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [profiles, setProfiles] = useState<Profile[]>([]);
  const [books, setBooks] = useState<Book[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isGoogleReady, setIsGoogleReady] = useState(false);

  // Load initial data
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      const parsed = JSON.parse(saved);
      // Migration: Ensure new fields exist on old data
      const loadedProfiles = (parsed.profiles || [INITIAL_PROFILE]).map((p: any) => ({
          ...p,
          isPrivacyMode: p.isPrivacyMode ?? false 
      }));

      setProfiles(loadedProfiles);
      setBooks(parsed.books || [INITIAL_BOOK]);
      setTransactions(parsed.transactions || []);

      const current = (loadedProfiles as Profile[])?.find(p => p.isCurrent);
      if (current?.googleClientId && window.gapi) {
        initGoogleDrive(current.googleClientId);
      }
    } else {
      setProfiles([INITIAL_PROFILE]);
      setBooks([INITIAL_BOOK]);
      setTransactions([]);
    }
  }, []);

  // Save on change
  useEffect(() => {
    if (profiles.length > 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ profiles, books, transactions }));
    }
  }, [profiles, books, transactions]);

  const currentProfile = profiles.find(p => p.isCurrent) || profiles[0] || null;

  // --- Actions ---

  const addProfile = (name: string) => {
    const newProfile: Profile = {
      id: uuidv4(),
      name,
      isCurrent: true,
      themePreference: 'system',
      isPrivacyMode: false,
      syncFrequency: SyncFrequency.OFF
    };

    const updatedProfiles = profiles.map(p => ({ ...p, isCurrent: false }));
    setProfiles([...updatedProfiles, newProfile]);

    const newBook: Book = {
      id: uuidv4(),
      profileId: newProfile.id,
      name: 'My Wallet',
      currency: 'USD',
      color: 'bg-emerald-500'
    };
    setBooks(prev => [...prev, newBook]);
  };

  const switchProfile = (id: string) => {
    setProfiles(prev => prev.map(p => ({
      ...p,
      isCurrent: p.id === id
    })));
  };

  const updateProfileSettings = (id: string, updates: Partial<Profile>) => {
    setProfiles(prev => prev.map(p => p.id === id ? { ...p, ...updates } : p));
  };

  const togglePrivacyMode = () => {
    if (currentProfile) {
        updateProfileSettings(currentProfile.id, { isPrivacyMode: !currentProfile.isPrivacyMode });
    }
  };

  const addBook = (bookData: Omit<Book, 'id' | 'profileId'>) => {
    if (!currentProfile) return;
    const newBook: Book = {
      ...bookData,
      id: uuidv4(),
      profileId: currentProfile.id
    };
    setBooks(prev => [...prev, newBook]);
  };

  const updateBook = (id: string, updates: Partial<Book>) => {
      setBooks(prev => prev.map(b => b.id === id ? { ...b, ...updates } : b));
  };

  const deleteBook = (id: string) => {
    setBooks(prev => prev.filter(b => b.id !== id));
    setTransactions(prev => prev.filter(t => t.bookId !== id));
  };

  const addTransaction = (txData: Omit<Transaction, 'id' | 'createdAt'>) => {
    const newTx: Transaction = {
      ...txData,
      id: uuidv4(),
      createdAt: Date.now()
    };
    setTransactions(prev => [newTx, ...prev]);
  };

  const updateTransaction = (id: string, updates: Partial<Transaction>) => {
      setTransactions(prev => prev.map(t => t.id === id ? { ...t, ...updates } : t));
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  // --- Import / Export ---

  const downloadTemplate = useCallback(() => {
    const blob = new Blob([SAMPLE_CSV], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'expenses_template.csv';
    a.click();
    window.URL.revokeObjectURL(url);
  }, []);

  const exportData = useCallback(() => {
    if (!currentProfile) return;
    const profileBookIds = books.filter(b => b.profileId === currentProfile.id).map(b => b.id);
    const profileTransactions = transactions.filter(t => profileBookIds.includes(t.bookId));

    const csv = generateCSV(profileTransactions, books, DEFAULT_CATEGORIES);
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `ET_${currentProfile.name.replace(/\s+/g, '_')}_${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
    window.URL.revokeObjectURL(url);
  }, [currentProfile, books, transactions]);

  const importData = async (csvText: string): Promise<{ success: boolean; message: string }> => {
    try {
      if (!currentProfile) throw new Error("No profile selected");
      const rows = parseCSV(csvText);
      const newTransactions: Transaction[] = [];
      let importedCount = 0;

      for (const row of rows) {
        let book = books.find(b => b.name === row['Book'] && b.profileId === currentProfile.id);
        if (!book) {
            const newBookId = uuidv4();
            const newBook: Book = {
                id: newBookId,
                profileId: currentProfile.id,
                name: row['Book'] || 'Imported Book',
                currency: 'USD',
                color: 'bg-gray-500'
            };
            setBooks(prev => [...prev, newBook]);
            book = newBook;
        }

        const cat = DEFAULT_CATEGORIES.find(c => c.name === row['Category']) || DEFAULT_CATEGORIES[6];

        if (row['Amount'] && row['Date']) {
            newTransactions.push({
                id: uuidv4(),
                bookId: book.id,
                amount: parseFloat(row['Amount']),
                type: row['Type'] === 'INCOME' ? TransactionType.INCOME : TransactionType.EXPENSE,
                categoryId: cat.id,
                date: row['Date'],
                note: row['Note'] || '',
                createdAt: Date.now()
            });
            importedCount++;
        }
      }
      setTransactions(prev => [...newTransactions, ...prev]);
      return { success: true, message: `Successfully imported ${importedCount} transactions.` };
    } catch (e: any) {
      return { success: false, message: e.message || "Failed to import CSV" };
    }
  };

  // --- Google Drive Integration ---

  const initGoogleDrive = async (clientId: string) => {
    try {
      if (!window.gapi || !window.google) {
        console.warn("Google API scripts not loaded");
        return;
      }

      await driveService.initGapiClient();

      driveService.initGisClient(clientId, (response) => {
        if(response.access_token && currentProfile) {
           updateProfileSettings(currentProfile.id, { googleAccessToken: response.access_token });
           driveService.setAccessToken(response.access_token);
        }
      });
      setIsGoogleReady(true);
    } catch (e) {
      console.error("Failed to init Google Drive", e);
    }
  };

  const signInToGoogle = async () => {
     if(!isGoogleReady) return;
     driveService.requestAccessToken();
  };

  const signOutFromGoogle = async () => {
    if(currentProfile) {
      updateProfileSettings(currentProfile.id, { googleAccessToken: undefined });
    }
  };

  const syncWithDrive = async () => {
    if (!currentProfile?.googleAccessToken) {
       await signInToGoogle();
       return; 
    }
    const data = JSON.stringify({
       profile: currentProfile,
       books: books.filter(b => b.profileId === currentProfile.id),
       transactions: transactions.filter(t => books.find(b => b.id === t.bookId)?.profileId === currentProfile.id)
    });

    try {
       await driveService.uploadFile(DRIVE_FILE_NAME, data);
       updateProfileSettings(currentProfile.id, { lastSyncedAt: Date.now() });
       // We'll let the UI handle success toast
    } catch(e) {
       console.error(e);
       throw e; // Propagate error
    }
  };

  const value = {
    profiles,
    books,
    transactions,
    categories: DEFAULT_CATEGORIES,
    currentProfile,
    addProfile,
    switchProfile,
    updateProfileSettings,
    togglePrivacyMode,
    addBook,
    updateBook,
    deleteBook,
    addTransaction,
    updateTransaction,
    deleteTransaction,
    importData,
    exportData,
    downloadTemplate,
    initGoogleDrive,
    signInToGoogle,
    signOutFromGoogle,
    syncWithDrive,
    isGoogleReady
  };

  return <DataContext.Provider value={value}>{children}</DataContext.Provider>;
};

export const useData = () => {
  const context = useContext(DataContext);
  if (!context) throw new Error("useData must be used within DataProvider");
  return context;
};

